def run(controller):
    controller.reset()
    limits = controller.get_limits()
    max_signal = limits['maximum_signal']
    max_gain = limits['maximum_gain']

    if max_signal >= 40000:
        gain = 64
    else:
        gain = 16

    controller.configure(atime=100, astep=999, gain=gain)
    controller.set_rgb(40, 60, 20)
    result = controller.measure()
    channels = result['channels']

    for _ in range(3):
        ch_max = channels[0]
        if channels[1] > ch_max:
            ch_max = channels[1]
        if channels[2] > ch_max:
            ch_max = channels[2]
        if channels[3] > ch_max:
            ch_max = channels[3]
        if channels[4] > ch_max:
            ch_max = channels[4]
        if channels[5] > ch_max:
            ch_max = channels[5]
        if channels[6] > ch_max:
            ch_max = channels[6]
        if channels[7] > ch_max:
            ch_max = channels[7]

        ch_min = channels[0]
        if channels[1] < ch_min:
            ch_min = channels[1]
        if channels[2] < ch_min:
            ch_min = channels[2]
        if channels[3] < ch_min:
            ch_min = channels[3]
        if channels[4] < ch_min:
            ch_min = channels[4]
        if channels[5] < ch_min:
            ch_min = channels[5]
        if channels[6] < ch_min:
            ch_min = channels[6]
        if channels[7] < ch_min:
            ch_min = channels[7]

        if ch_max > max_signal:
            gain = gain // 4
            controller.configure(atime=100, astep=999, gain=gain)
            result = controller.measure()
            channels = result['channels']
        elif ch_min < 1:
            if gain < max_gain:
                new_gain = gain * 4
                if new_gain > max_gain:
                    new_gain = max_gain
                gain = new_gain
                controller.configure(atime=100, astep=999, gain=gain)
                result = controller.measure()
                channels = result['channels']
            else:
                break
        else:
            break

    controller.clear()
    return result

